def main():
    n = int(input())
    arr = list(map(int, input().split()))
    ans_neg = 0
    ans_pos = 0
    cnt_neg = 0
    cnt_pos = 0
    for i in range(n):
        if arr[i] < 0:
            cnt_neg += 1
        elif arr[i] > 0:
            cnt_pos += 1
        else:
            cnt_neg = 0
            cnt_pos = 0
        ans_neg += cnt_neg
        ans_pos += cnt_pos
    print(ans_neg, ans_pos)


if __name__ == '__main__':
    main()
